INSERT INTO public.about_us_configs (id,header_badge,header_title,header_description,primary_button_text,secondary_button_text,differentials,achievements,created_at,updated_at) VALUES
	 ('44c5b357-d2be-4168-ba59-0f94c379c612','QUEM SOMOS','Mais de 20 anos de expertise em Comércio Exterior','Atuamos com excelência em todos os portos, aeroportos e fronteiras do Brasil, garantindo que sua carga chegue ao destino final sem imprevistos e com o melhor custo-benefício.1','Conheça nossa história','Fale conosco','[{"id": "feat-1", "desc": "Taxa de sucesso em processos de Ex-Tarifário", "title": "98% de aprovação no MDIC1"}, {"id": "feat-2", "desc": "Especialistas dedicados para cada cliente", "title": "Atendimento personalizado"}, {"id": "feat-3", "desc": "Processos 100% legais e auditáveis", "title": "Conformidade regulatória total"}]','[{"id": "ach-1", "desc": "Redução de até 100% no II — alíquota 0%", "title": "Ex-Tarifário"}, {"id": "ach-2", "desc": "Para os nossos clientes", "title": "R$ 480M+ economizados"}, {"id": "ach-3", "desc": "Indústria, Agro, Tech, Infraestrutura...", "title": "13+ setores"}, {"id": "ach-4", "desc": "Fundador & Especialista", "title": "Matheus Diniz"}]','2026-05-09 06:41:53.342412','2026-05-09 06:42:12.632124');
INSERT INTO public.air_representation_configs (id,header_badge,header_title_dark,header_title_highlight,import_sections,export_sections,created_at,updated_at,header_description) VALUES
	 ('1580eca3-4ac6-49e1-894f-22bc6d2d4bb7','REPRESENTAÇÃO ESTRATÉGICA','Representações','Aéreas','[{"id": "imp-1", "desc": "Sendo a extensão da sua empresa, atuamos como uma ponte estratégica, assumindo de forma profissional as operações nos aeroportos GRU (Guarulhos) e VCP (Viracopos).", "icon": "Radar", "image": "a6fe1653aacd0a96ae64-exempl1export.jpg", "title": "Representação em Aeroportos", "topics": "Soluções ágeis, seguras e personalizadas\nVasto conhecimento técnico e operacional\nAtendimento exclusivo e dedicado\nParceiro estratégico preparado para complexidade"}, {"id": "imp-2", "desc": "Somos referência no segmento, com atuação ativa desde o período de implantação do CCT Importação.", "icon": "Landmark", "title": "CCT Importação e CE Mercante", "topics": "Rastreabilidade em cada etapa do processo\nFollow-up atualizado em tempo real\nOperações 24 horas por dia, 7 dias por semana\nEquipe pronta para lançamentos em finais de semana e feriados"}, {"id": "imp-3", "desc": "Na Avant, entendemos que a eficiência na distribuição é decisiva para o sucesso das operações de importação.", "icon": "Truck", "title": "Distribuição de Cargas", "topics": "Frota credenciada e parceiros estratégicos\nProcessos padronizados de alta qualidade\nSegurança, agilidade e rastreabilidade total\nRedução de custos e otimização de prazos"}]','[{"id": "exp-1", "desc": "Exportação aérea exige velocidade, precisão e total conformidade. Oferecemos um serviço completo de preparação de cargas para exportações aéreas.", "icon": "Plane", "title": "Preparação de cargas", "topics": "Velocidade e precisão documental\nMáxima segurança e eficiência\nKnow-how em comércio exterior\nRedução de custos operacionais"}, {"id": "exp-2", "desc": "Seu cliente não pode esperar? Cuidamos disso! Oferecemos soluções rápidas, especializadas e seguras em exportação aérea.", "icon": "Zap", "title": "Operações Urgentes", "topics": "Atuação direta nos principais aeroportos\nEstrutura própria e equipe especializada\nProcessos ágeis da coleta ao embarque\nResultados seguros e eficientes"}, {"id": "exp-3", "desc": "A exportação aérea exige precisão documental e total conformidade com os órgãos reguladores.", "icon": "Monitor", "title": "Sistemas comércio exterior", "topics": "Precisão documental e conformidade\nLançamentos no Portal Único\nE-awb especializado\nTerceirização ágil e segura"}, {"id": "exp-4", "desc": "Antes da carga chegar ao aeroporto, cada detalhe da operação faz diferença no sucesso da exportação.", "icon": "PackageCheck", "title": "Transporte e Pré-Embarque", "topics": "Soluções completas de transporte\nCheck-list físico e etiquetagem\nPré-cadastro nos terminais\nAtualizações em tempo real"}]','2026-05-09 18:10:07.047593','2026-05-09 19:18:25.610893','Integramos operações de importação e exportação com foco em agilidade, segurança e conformidade total nos principais aeroportos do Brasil.');
INSERT INTO public.work_steps_configs (id,header_badge,header_title,header_description,cta_text,steps,created_at,updated_at) VALUES
	 ('96b97e2e-41b5-40aa-923d-3d205a97e59b','COMO TRABALHAMOS','Nossa abordagem em 4 etapas','Um fluxo de trabalho transparente e eficiente desenhado para mitigar riscos e maximizar resultados.','Falar com um especialista1','[{"id": "step-1", "desc": "Avaliamos a situação da empresa, os produtos e os objetivos para identificar as melhores oportunidades e regimes aduaneiros aplicáveis.", "title": "Análise e Diagnóstico"}, {"id": "step-2", "desc": "Definimos a estratégia mais adequada para cada operação, com foco em redução de custos, conformidade legal e agilidade no processo.", "title": "Planejamento e Estratégia"}, {"id": "step-3", "desc": "Realizamos todos os procedimentos junto aos órgãos competentes (Receita Federal, MDIC, Siscomex), monitorando cada etapa e respondendo às exigências com agilidade.", "title": "Execução e Acompanhamento"}, {"id": "step-4", "desc": "Entregamos o resultado esperado e mantemos o relacionamento ativo, garantindo que sua empresa esteja sempre em conformidade e aproveitando os benefícios disponíveis.", "title": "Resultado e Continuidade"}]','2026-05-09 06:32:33.201003','2026-05-09 06:32:58.635449');
