INSERT INTO public.testimonials_configs (id,header_badge,header_title,header_description,testimonials,created_at,updated_at) VALUES
	 ('de46832c-2a08-4660-83fe-c5c399b40763','DEPOIMENTOS1','O que nossos clientes dizem','Alguns depoimentos de pessoas e empresas que acreditam em nosso trabalho.1','[{"id": "test-1", "name": "Osvaldo Mendes1", "role": "CEO1", "content": "Atendimento personalizado, rápido, eficiente e proativo. Experiência positiva, recomendamos."}, {"id": "test-2", "name": "Hewerton Precioso", "role": "Engenheiro Eletrônico — Especializado em partes e peças", "content": "Grata surpresa com o atendimento e com os resultados do trabalho contratado. Alto nível moral e intelectual, rapidez e precisão nas respostas e disponibilidade para pesquisar dúvidas inerentes da dinâmica da legislação. Gratidão!"}, {"id": "test-3", "name": "Diogo Fazolo", "role": "Mestre em Direito — Especialista em Direito Aduaneiro", "content": "Conheço a empresa já há alguns anos, atendimento excelente, muita competência e conhecimento da legislação aduaneira. Tenho plena confiança em indicar o trabalho do Sr. Matheus Diniz."}, {"id": "test-1778309650100", "name": "6465", "role": "4645", "content": "646"}]','2026-05-09 06:54:21.904862','2026-05-09 06:54:21.904862');
