	 ('e001c70a-e8e0-471c-a0ae-eea738e9f094','SEGMENTOS1','Setores que atendemos','Soluções logísticas integradas e personalizadas para as demandas mais exigentes do mercado global.1','[{"id": "sec-1", "title": "AGENTES DE CARGA", "iconName": "Users"}, {"id": "sec-2", "title": "COMISSÁRIAS", "iconName": "Shield"}, {"id": "sec-3", "title": "CARGAS AÉREAS", "iconName": "Globe"}, {"id": "sec-4", "title": "CARGAS PERIGOSAS", "iconName": "Zap"}, {"id": "sec-5", "title": "CARGAS URGENTES", "iconName": "Clock"}, {"id": "sec-6", "title": "CARGAS DE PROJETO", "iconName": "Box"}, {"id": "sec-7", "title": "IMPORTADORES", "iconName": "Building"}, {"id": "sec-8", "title": "EXPORTADORES", "iconName": "Truck"}, {"id": "sec-9", "title": "GRU AIRPORT", "iconName": "Target"}, {"id": "sec-10", "title": "VIRACOPOS (VCP)", "iconName": "Target"}, {"id": "sec-11", "title": "OPERAÇÕES COMPLEXAS", "iconName": "Hammer"}, {"id": "sec-12", "title": "LOGÍSTICA REVERSA", "iconName": "RefreshCw"}, {"id": "sec-13", "title": "PHARMA", "iconName": "Pill"}]','2026-05-09 06:53:46.45451','2026-05-09 06:53:56.853712');
