	 ('37e69f6f-5747-4cf1-9024-a0382db7ac19','LOGÍSTICA AÉREA & SERVIÇOS ADUANEIROS3','Seu parceiro estratégico em Aeroportos GRU | VCP3','Soluções ágeis para agentes de carga e comissárias. Controle a informação, controle o resultado e acelere seu desembaraço aduaneiro.','Falar conosco','Quem somos','[{"id": "feat-1", "text": "+20 anos de experiência"}, {"id": "feat-2", "text": "Empresa 100% brasileira"}, {"id": "feat-3", "text": "Guarulhos, SP"}]','[{"id": "serv-1", "desc": "Expertise global em todos os portos e aeroportos.", "title": "Assessoria Aduaneira"}, {"id": "serv-2", "desc": "Otimização de impostos e regimes especiais.", "title": "Consultoria Tributária"}, {"id": "serv-3", "desc": "Conformidade total com a legislação vigente.", "title": "Segurança Jurídica"}, {"id": "serv-4", "desc": "Suporte especializado em cada etapa do processo.", "title": "Equipe Dedicada"}]','[{"id": "stat-1", "label": "CLIENTES ATENDIDOS", "value": "500+"}, {"id": "stat-2", "label": "ANOS DE EXPERIÊNCIA", "value": "20+"}, {"id": "stat-3", "label": "SATISFAÇÃO", "value": "98%"}]','[{"id": "sstat-1", "label": "ANOS DE EXPERIÊNCIA NO MERCADO", "value": "20+"}, {"id": "sstat-2", "label": "CLIENTES ATENDIDOS", "value": "500+"}, {"id": "sstat-3", "label": "TAXA DE RETENÇÃO E FIDELIDADE", "value": "98%"}, {"id": "sstat-4", "label": "SEGURANÇA JURÍDICA", "value": "100%"}]','2026-05-09 06:03:28.954764','2026-05-09 06:06:18.608504','NOSSOS PRINCIPAIS SERVIÇOS');
